import { CaretDownOutlined } from "@ant-design/icons"
import { Avatar, Col, Input, Row, Select, Tooltip, Tree } from "antd"
import React, { useEffect, useMemo, useState } from "react"
import { useSelector } from "react-redux"
import SelectCustom from "src/components/Select/SelectCustom"
import { GUIDE_EMPTY, SYSTEM_KEY } from "src/constants/constants"
import { removeDiacritics } from "src/lib/stringsUtils"
import { getListComboByKey } from "src/lib/utils"

const { Search } = Input

export const MemoTooltip = Tooltip || React.memo(Tooltip)

const getParentKey = (key, tree) => {
  for (const node of tree) {
    if (node.children) {
      if (node.children.some(child => child.key === key)) {
        return node.key
      }
      const parentKey = getParentKey(key, node.children)
      if (parentKey) return parentKey
    }
  }
  return null
}

// Hàm xác định style dựa trên trạng thái cho tree nodes
const getStatusStyle = status => {
  switch (status) {
    case 4: // Ngừng hoạt động
    case 5: // Bị từ chối duyệt
      return {
        color: "#ff4d4f",
        textDecoration: "line-through",
      }
    case 1: // Đang tập hợp
    case 2: // Chờ phê duyệt
      return {
        color: "#fa8c16",
      }
    case 3: // Hoạt động
    default:
      return {
        color: "#000000",
      }
  }
}

// Hàm xác định style dựa trên trạng thái cho tooltip (màu sáng hơn cho nền tooltip tối)
const getTooltipStatusStyle = status => {
  switch (status) {
    case 4: // Ngừng hoạt động
    case 5: // Bị từ chối duyệt
      return {
        color: "#ff7875",
        textDecoration: "line-through",
      }
    case 1: // Đang tập hợp
    case 2: // Chờ phê duyệt
      return {
        color: "#ffa940",
      }
    case 3: // Hoạt động
    default:
      return {
        color: "#ffffff", // Màu trắng cho trạng thái hoạt động trong tooltip
      }
  }
}

// Hàm lấy tên trạng thái để hiển thị trong tooltip
const getStatusText = (status, listSystemKey) => {
  const statusList =
    getListComboByKey(SYSTEM_KEY?.ASSOCIATION_STATUS, listSystemKey) || []
  const statusItem = statusList.find(item => +item.CodeValue === status)
  return statusItem?.Description || ""
}

const SearchTree = ({
  selectedNode,
  setSelectedNote = () => {},
  treeDataDefault = [],
  dataList = [],
}) => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [expandedKeys, setExpandedKeys] = useState(
    dataList.map(item => {
      return item.key
    }),
  )
  const [searchValue, setSearchValue] = useState("")
  const [selectedStatus, setSelectedStatus] = useState(3)
  const [autoExpandParent, setAutoExpandParent] = useState(true)

  const onExpand = newExpandedKeys => {
    setExpandedKeys(newExpandedKeys)
    setAutoExpandParent(false)
  }

  const onStatusChange = value => {
    setSelectedStatus(value)
    setAutoExpandParent(true)
  }

  const onChange = e => {
    const { value } = e.target
    const textSearch = removeDiacritics(value.toLowerCase())

    const findMatchingNodes = (data, matchingKeys = new Set()) => {
      data.forEach(item => {
        const textMatch =
          !textSearch || item.removeDiacriticsTitle.indexOf(textSearch) > -1
        const statusMatch =
          selectedStatus === 0 || item.Status === selectedStatus

        if (textMatch && statusMatch) {
          matchingKeys.add(item.key)
          const parentKey = getParentKey(item.key, treeDataDefault)
          if (parentKey) {
            matchingKeys.add(parentKey)
          }
        }

        if (item.children) {
          findMatchingNodes(item.children, matchingKeys)
        }
      })
      return matchingKeys
    }

    const matchingKeys = findMatchingNodes(dataList)
    setExpandedKeys(Array.from(matchingKeys))
    setSearchValue(value)
    setAutoExpandParent(true)
  }

  const treeData = useMemo(() => {
    const textSearch = removeDiacritics(searchValue.toLowerCase())

    const loop = data =>
      data
        .map(item => {
          const strTitle = item.title || ""
          const index = item.removeDiacriticsTitle.indexOf(textSearch)
          const beforeStr = strTitle.substring(0, index)
          const midStr = strTitle.substring(index, index + textSearch.length)
          const afterStr = strTitle.slice(index + textSearch.length)

          // Lấy style dựa trên trạng thái cho tree node
          const statusStyle = getStatusStyle(item.Status)
          // Lấy style dựa trên trạng thái cho tooltip
          const tooltipStatusStyle = getTooltipStatusStyle(item.Status)
          const statusText = getStatusText(item.Status, listSystemKey)

          const createName = styleToUse => {
            return index > -1 ? (
              <span style={styleToUse}>
                {beforeStr}
                <span
                  className="site-tree-search-value"
                  style={{
                    color: "#f10101",
                    backgroundColor: "#ffeb3b",
                    ...styleToUse,
                  }}
                >
                  {midStr}
                </span>
                {afterStr} ({item?.MemberNo || 0})
              </span>
            ) : (
              <span style={styleToUse}>
                {strTitle} ({item?.MemberNo || 0})
              </span>
            )
          }

          const name = createName(statusStyle)
          const tooltipName = createName(tooltipStatusStyle)

          const titleRender = (className, nameToRender) => (
            <div className={className || ""} style={{ padding: "3px 5px" }}>
              <Avatar
                size={24}
                src={
                  item?.Image ? (
                    <img src={item?.Image} alt="avatar" />
                  ) : undefined
                }
                style={{
                  backgroundColor: "#7265e6",
                  verticalAlign: "middle",
                  fontSize: "16px",
                }}
                className="mr-8"
              >
                {item?.AssociationName?.[0] || ""}
              </Avatar>
              <span>{nameToRender}</span>
            </div>
          )

          const title = (
            <MemoTooltip
              title={
                <div>
                  <div>{titleRender("", tooltipName)}</div>
                  <div style={{ marginTop: 4, fontSize: "12px" }}>
                    <strong>Trạng thái:</strong>{" "}
                    <span style={tooltipStatusStyle}>{statusText}</span>
                  </div>
                  <div style={{ fontSize: "12px" }}>
                    <strong>Số thành viên:</strong> {item?.MemberNo || 0}
                  </div>
                </div>
              }
              key={item.key}
            >
              {titleRender("max-line1", name)}
            </MemoTooltip>
          )

          const currentNodeMatch =
            (selectedStatus === 0 || item.Status === selectedStatus) &&
            (!textSearch || item.removeDiacriticsTitle.indexOf(textSearch) > -1)

          if (item.children) {
            const filteredChildren = loop(item.children)
            const hasValidChildren = filteredChildren.length > 0

            if (currentNodeMatch || hasValidChildren) {
              return { title, key: item.key, children: filteredChildren }
            }
            return null
          }

          if (currentNodeMatch) {
            return { title, key: item.key }
          }

          return null
        })
        .filter(Boolean)

    return loop(treeDataDefault)
  }, [searchValue, treeDataDefault, selectedStatus, listSystemKey])

  useEffect(() => {
    if (!dataList?.length) return

    const textSearch = removeDiacritics(searchValue.toLowerCase())

    const findMatchingNodes = (data, matchingKeys = new Set()) => {
      data.forEach(item => {
        const textMatch =
          !textSearch || item.removeDiacriticsTitle.indexOf(textSearch) > -1
        const statusMatch =
          selectedStatus === 0 || item.Status === selectedStatus

        if (statusMatch && textMatch) {
          matchingKeys.add(item.key)
          const parentKey = getParentKey(item.key, treeDataDefault)
          if (parentKey) {
            matchingKeys.add(parentKey)
          }
        }

        if (item.children) {
          findMatchingNodes(item.children, matchingKeys)
        }
      })
      return matchingKeys
    }

    const matchingKeys = findMatchingNodes(dataList)
    setExpandedKeys(Array.from(matchingKeys))
  }, [dataList, selectedStatus, searchValue, treeDataDefault])

  return (
    <div>
      <Row gutter={[8, 8]}>
        <Col span={16}>
          <Search
            allowClear
            style={{ marginBottom: 8 }}
            placeholder="Tìm kiếm tên hiệp hội"
            onChange={onChange}
            value={searchValue}
            enterButton
          />
        </Col>
        <Col span={8}>
          <SelectCustom
            placeholder="Trạng thái"
            defaultValue={0}
            value={selectedStatus}
            onChange={onStatusChange}
          >
            {getListComboByKey(
              SYSTEM_KEY?.ASSOCIATION_STATUS,
              listSystemKey,
            )?.map(i => (
              <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                <span style={getStatusStyle(+i.CodeValue)}>
                  {i?.Description}
                </span>
              </Select.Option>
            ))}
          </SelectCustom>
        </Col>
      </Row>

      <Tree
        height={900}
        showLine
        switcherIcon={
          <CaretDownOutlined style={{ fontSize: 16, marginTop: 5 }} />
        }
        defaultExpandAll
        onExpand={onExpand}
        expandedKeys={expandedKeys}
        autoExpandParent={autoExpandParent}
        treeData={treeData}
        defaultSelectedKeys={[GUIDE_EMPTY]}
        selectedKeys={[selectedNode?.key]}
        onSelect={(_, e) => {
          setSelectedNote(e?.node)
        }}
      />
    </div>
  )
}

export default SearchTree
