import styled from "styled-components"

export const AssociationStyle = styled.div`
  .detail-box {
    background: #fff;
    border-radius: 10px;
    padding: 8px 32px;
    height: calc(100vh - 167px);
  }
`

export const ListUnitStyled = styled.div`
  position: sticky;
  top: 58px;
  background: #ffffff;
  border: 1px solid #dddddd;
  border-radius: 10px;
  overflow: hidden auto;
  padding: 10px;
  height: calc(100vh - 62px);

  .unit-item {
    padding: 6px 12px;
    margin-bottom: 8px;
    background: #fff;
    cursor: pointer;
    &:hover {
      background: #f0f0f0;
    }
    &.active {
      background-color: #0087d0;
      color: #fff;
    }
  }
`
export const TreeAnchorStyled = styled.div`
  position: sticky;
  top: 58px;
  background: #ffffff;
  border: 1px solid #dddddd;
  border-radius: 10px;
  overflow: hidden auto;
  padding: 10px;
  height: calc(100vh - 167px);
  .ant-tree .ant-tree-switcher-leaf-line {
    &::after {
      border-bottom: 1px solid #646464;
    }
    &::before {
      border-inline-end: 1px solid #646464;
    }
  }
  .ant-tree-show-line .ant-tree-indent-unit:before {
    border-inline-end: 1px solid #646464;
  }
  .ant-tree-node-selected,
  .ant-tree-node-content-wrapper:hover {
    /* background-color: transparent !important; */
  }
  .ant-tree-node-selected .ant-tree-title {
    color: #000;
    font-weight: 600;
  }
`
